class Solution:
    def maxDepthAfterSplit(self, seq: str) -> List[int]:
        res = []
        d = 0
        for c in seq:
            if c == '(':
                d += 1
                res.append(d % 2)
            else:
                res.append(d % 2)
                d -= 1
        return res
